import React, { useEffect, useRef } from 'react';



function DottedSphere({ size = 1000, className = '' }) {

  const canvasRef = useRef(null);

  const animationRef = useRef(null);

  const timeRef = useRef(0);



  useEffect(() => {

    const canvas = canvasRef.current;

    const ctx = canvas.getContext('2d');

    const dpr = window.devicePixelRatio || 1;



    canvas.width = size * dpr;

    canvas.height = size * dpr;

    ctx.scale(dpr, dpr);



    const centerX = size / 2;

    const centerY = size / 2;



    // Vòng lớn hơn

    const layers = [

      { rx: size * 0.52, ry: size * 0.26, rings: 18, color: 'cyan' },

      { rx: size * 0.48, ry: size * 0.36, rings: 16, color: 'purple' },

      { rx: size * 0.44, ry: size * 0.42, rings: 14, color: 'blue' },

    ];



    const layerDots = layers.map((layer) => {

      const dots = [];

      for (let ring = 4; ring <= layer.rings; ring++) {

        const scale = ring / layer.rings;

        const rx = layer.rx * scale;

        const ry = layer.ry * scale;

        const numDots = Math.floor(28 + ring * 5);



        for (let i = 0; i < numDots; i++) {

          const angle = (i / numDots) * Math.PI * 2;

          dots.push({

            angle,

            rx,

            ry,

            ring,

            scale // Để tính size dot

          });

        }

      }

      return dots;

    });



    function draw() {

      ctx.clearRect(0, 0, size, size);



      const t = timeRef.current;



      // Background glow

      const glow = ctx.createRadialGradient(centerX, centerY, 0, centerX, centerY, size / 2);

      glow.addColorStop(0, 'rgba(120, 80, 255, 0.1)');

      glow.addColorStop(0.5, 'rgba(80, 200, 255, 0.05)');

      glow.addColorStop(1, 'rgba(0, 0, 0, 0)');

      ctx.fillStyle = glow;

      ctx.fillRect(0, 0, size, size);



      layers.forEach((layer, layerIdx) => {

        // Di chuyển nhanh hơn (x2)

        const offsetX = Math.sin(t * 1.0 + layerIdx * 2) * 20;

        const offsetY = Math.cos(t * 0.6 + layerIdx * 1.5) * 15;

        const tilt = Math.sin(t * 0.4 + layerIdx) * 0.15;



        layerDots[layerIdx].forEach(dot => {

          let x = Math.cos(dot.angle) * dot.rx;

          let y = Math.sin(dot.angle) * dot.ry;



          const tiltedY = y * Math.cos(tilt);

          const z = y * Math.sin(tilt);



          const finalX = centerX + x + offsetX;

          const finalY = centerY + tiltedY + offsetY - 40 + layerIdx * 50;



          const depth = (z + size / 2) / size;

          const alpha = 0.25 + depth * 0.5;



          // Dots bên trong nhỏ, bên ngoài lớn

          const dotSize = 0.8 + dot.scale * 2.2;



          let color;

          let glowColor;

          if (layerIdx === 0) {

            color = `rgba(80, 220, 255, ${alpha})`;

            glowColor = `rgba(80, 220, 255, ${alpha * 0.1})`;

          } else if (layerIdx === 1) {

            color = `rgba(180, 120, 255, ${alpha})`;

            glowColor = `rgba(180, 120, 255, ${alpha * 0.1})`;

          } else {

            color = `rgba(100, 140, 255, ${alpha})`;

            glowColor = `rgba(100, 140, 255, ${alpha * 0.1})`;

          }



          // Glow chỉ cho dots lớn

          if (dot.scale > 0.6) {

            ctx.beginPath();

            ctx.arc(finalX, finalY, dotSize * 3, 0, Math.PI * 2);

            ctx.fillStyle = glowColor;

            ctx.fill();

          }



          ctx.beginPath();

          ctx.arc(finalX, finalY, dotSize, 0, Math.PI * 2);

          ctx.fillStyle = color;

          ctx.fill();

        });

      });



      timeRef.current += 0.016;

      animationRef.current = requestAnimationFrame(draw);

    }



    draw();



    return () => {

      if (animationRef.current) {

        cancelAnimationFrame(animationRef.current);

      }

    };

  }, [size]);



  return (

    <div className={`absolute pointer-events-none ${className}`}>

      <canvas 

        ref={canvasRef}

        style={{ width: size, height: size }}

      />

    </div>

  );

}



export default DottedSphere;
